"""day26.sprint_export_utils

Utility functions for exporting sprint data to common formats.

The module intentionally keeps dependencies to the Python standard library so it
can be reused across scripts and CI jobs.

Supported exports:
- JSON (pretty-printed, UTF-8)
- CSV (header inferred from records)
- Markdown (GitHub-flavored table when possible)

Expected input shapes
---------------------
The functions are designed to be permissive:

- If *data* is a list/tuple of dict-like records, it is treated as a table.
- If *data* is a dict, it is treated as a mapping (for CSV this becomes a
  two-column key/value file).
- For other objects, the module tries to coerce to a serializable form via
  ``__dict__``.

"""

from __future__ import annotations

import csv
import json
from dataclasses import asdict, is_dataclass
from pathlib import Path
from typing import Any, Iterable, Mapping, Sequence

__all__ = [
    "export_to_json",
    "export_to_csv",
    "export_to_markdown",
]


def _to_path(path: str | Path) -> Path:
    p = Path(path)
    if p.parent:
        p.parent.mkdir(parents=True, exist_ok=True)
    return p


def _normalize(obj: Any) -> Any:
    """Best-effort conversion to JSON-serializable Python primitives."""
    if obj is None:
        return None

    if is_dataclass(obj):
        return _normalize(asdict(obj))

    # Common primitive containers
    if isinstance(obj, (str, int, float, bool)):
        return obj

    if isinstance(obj, Path):
        return str(obj)

    if isinstance(obj, Mapping):
        return {str(k): _normalize(v) for k, v in obj.items()}

    if isinstance(obj, (list, tuple, set)):
        return [_normalize(x) for x in obj]

    # Fallbacks
    if hasattr(obj, "__dict__"):
        return _normalize(vars(obj))

    return str(obj)


def export_to_json(data: Any, path: str | Path) -> None:
    """Export *data* to a UTF-8 JSON file.

    Args:
        data: Arbitrary sprint data structure.
        path: Output path.

    The JSON is pretty-printed with stable key ordering to improve diffs.
    """
    p = _to_path(path)
    normalized = _normalize(data)
    with p.open("w", encoding="utf-8", newline="\n") as f:
        json.dump(
            normalized,
            f,
            ensure_ascii=False,
            indent=2,
            sort_keys=True,
        )
        f.write("\n")


def _records_from_data(data: Any) -> tuple[list[dict[str, Any]], list[str]]:
    """Coerce *data* into (records, fieldnames) for table-like exports."""
    normalized = _normalize(data)

    # Table-like: list of dicts
    if isinstance(normalized, Sequence) and not isinstance(normalized, (str, bytes)):
        records: list[dict[str, Any]] = []
        fieldnames: list[str] = []
        field_set: set[str] = set()
        for item in normalized:
            if isinstance(item, Mapping):
                rec = {str(k): v for k, v in item.items()}
            else:
                # single value row
                rec = {"value": item}
            records.append(rec)
            for k in rec.keys():
                if k not in field_set:
                    field_set.add(k)
                    fieldnames.append(k)
        return records, fieldnames

    # Mapping-like: dict -> key/value table
    if isinstance(normalized, Mapping):
        records = [{"key": k, "value": v} for k, v in normalized.items()]
        return records, ["key", "value"]

    # Scalar fallback
    return [{"value": normalized}], ["value"]


def export_to_csv(data: Any, path: str | Path) -> None:
    """Export *data* to CSV.

    If *data* is a list of dict-like records, headers are inferred from the union
    of keys across all records (preserving first-seen order). If *data* is a
    mapping, a two-column ``key,value`` CSV is produced.
    """
    p = _to_path(path)
    records, fieldnames = _records_from_data(data)

    with p.open("w", encoding="utf-8", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames, extrasaction="ignore")
        writer.writeheader()
        for rec in records:
            writer.writerow({k: _csv_cell(rec.get(k)) for k in fieldnames})


def _csv_cell(value: Any) -> str:
    """Convert a cell value to a CSV-friendly string."""
    if value is None:
        return ""
    if isinstance(value, (str, int, float, bool)):
        return str(value)
    # For nested structures, store compact JSON
    return json.dumps(_normalize(value), ensure_ascii=False, sort_keys=True)


def export_to_markdown(data: Any, path: str | Path) -> None:
    """Export *data* to Markdown.

    - For a list of dict-like records: writes a GitHub-flavored markdown table.
    - For a mapping or scalar: writes a fenced JSON code block.
    """
    p = _to_path(path)
    normalized = _normalize(data)

    md: str
    if isinstance(normalized, Sequence) and not isinstance(normalized, (str, bytes)):
        records, fieldnames = _records_from_data(normalized)
        md = _markdown_table(records, fieldnames)
    else:
        md = "```json\n" + json.dumps(normalized, ensure_ascii=False, indent=2, sort_keys=True) + "\n```\n"

    with p.open("w", encoding="utf-8", newline="\n") as f:
        f.write(md)


def _markdown_table(records: Iterable[Mapping[str, Any]], fieldnames: Sequence[str]) -> str:
    """Render GitHub-flavored Markdown table."""

    def esc(text: str) -> str:
        # Escape pipes and newlines for table cells.
        return text.replace("|", "\\|").replace("\n", "<br>")

    headers = [esc(str(h)) for h in fieldnames]
    sep = ["---" for _ in fieldnames]

    lines = [
        "| " + " | ".join(headers) + " |",
        "| " + " | ".join(sep) + " |",
    ]

    for rec in records:
        row_cells: list[str] = []
        for k in fieldnames:
            v = rec.get(k)
            if v is None:
                s = ""
            elif isinstance(v, (str, int, float, bool)):
                s = str(v)
            else:
                s = json.dumps(_normalize(v), ensure_ascii=False, sort_keys=True)
            row_cells.append(esc(s))
        lines.append("| " + " | ".join(row_cells) + " |")

    return "\n".join(lines) + "\n"
